SELECT COUNT(*)
FROM sc
WHERE 1=1

    AND sc.studentID LIKE CONCAT('%', #{studentNo}, '%')


    AND sc.courseID LIKE CONCAT('%', #{courseNo}, '%')


    AND sc.BuyBook = #{buyTextbook}


    AND sc.Grade >= #{minGrade}


    AND sc.Grade >=  #{maxGrade}

SELECT sc.StudentID, sc.CourseID, sc.BuyBook, sc.Grade
FROM sc
WHERE 1=1

    AND sc.studentID LIKE CONCAT('%', #{studentNo}, '%')


    AND sc.courseID LIKE CONCAT('%', #{courseNo}, '%')


    AND sc.BuyBook = #{buyTextbook}


    AND sc.Grade >= #{minGrade}


    AND sc.Grade >= #{maxGrade}

LIMIT #{offset}, #{limit}
